-- ═══════════════════════════════════════════════════
-- 2. program_modes: free_chat + author_chat с welcome-данными
-- ═══════════════════════════════════════════════════

-- free_chat
INSERT INTO program_modes (
  program_id, mode_template_id, enabled, sort_order, access_type,
  welcome_mode_label, welcome_title, welcome_subtitle,
  welcome_ai_message, welcome_replies, color_class
)
SELECT
  p.id, mt.id, true, 9, 'paid',
  'Свободный чат',
  'Просто поговорить',
  'Любой вопрос по EQ через призму книги',
  E'Я EQ-коуч на основе книги Бредберри и Гривз. Неси любой вопрос — про свои эмоции, поведение других, сложные разговоры, стресс.\n\nЯ не пересказываю книгу, а помогаю:\n\n• назвать что происходит (теория в 2 предложения, не в 20)\n• разобрать твою конкретную ситуацию\n• если уместно — предложить 1-2 практики из 66\n\nС чего начнём?',
  '[
    {"text": "Расскажи про 4 навыка EQ вкратце", "type": "normal"},
    {"text": "У меня конкретная ситуация — разберём?", "type": "normal"},
    {"text": "Как развивать EQ если читал похожие книги?", "type": "normal"},
    {"text": "Не знаю о чём спросить", "type": "exit"}
  ]'::jsonb,
  'accent'
FROM programs p, mode_templates mt
WHERE p.slug = 'eq-2-0' AND mt.key = 'free_chat'
ON CONFLICT DO NOTHING;

-- author_chat
INSERT INTO program_modes (
  program_id, mode_template_id, enabled, sort_order, access_type,
  welcome_mode_label, welcome_title, welcome_subtitle,
  welcome_ai_message, welcome_replies, color_class
)
SELECT
  p.id, mt.id, true, 10, 'paid',
  'Разговор с автором',
  'Разговор с Бредберри',
  'AI в стиле Тревиса Бредберри',
  E'Привет, я Тревис. Со-автор «Эмоционального интеллекта 2.0» и соучредитель TalentSmart.\n\nСпрашивай как будто мы в кофейне в Сан-Диего — отвечаю прикладно, без академии. За спиной 20 лет данных на полмиллиона респондентов.\n\nЛюбимые темы: почему IQ переоценён, как реально работает нейропластичность, и что мы узнали про лидеров высшего звена.\n\nО чём говорим?',
  '[
    {"text": "Почему EQ важнее IQ?", "type": "normal"},
    {"text": "С чего начать если низкий по всем шкалам?", "type": "normal"},
    {"text": "Как измерить прогресс за 3 месяца?", "type": "normal"},
    {"text": "Что вы узнали про CEO и лидеров?", "type": "normal"}
  ]'::jsonb,
  'accent'
FROM programs p, mode_templates mt
WHERE p.slug = 'eq-2-0' AND mt.key = 'author_chat'
ON CONFLICT DO NOTHING;


